/**
 * Temporal Activities
 *
 * squareNumber: accepts an integer n and returns n * n.
 * This is a deterministic compute step executed by the Temporal worker.
 */

export async function squareNumber(n: number): Promise<number> {
  return n * n;
}

/**
 * Temporal Workflow: ParallelSquaresWorkflow
 *
 * Accepts an array of numbers, fans out by invoking the squareNumber activity
 * concurrently for every element via Promise.all (fan-out), then sums the
 * squared results (fan-in) and returns the total.
 *
 * NOTE: This file runs inside the Temporal workflow sandbox.
 * Only @temporalio/workflow imports are allowed here — no Node.js built-ins.
 */

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

// Proxy gives us a typed handle to the registered activities.
// startToCloseTimeout is the maximum time a single activity execution may run.
const { squareNumber } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
});

/**
 * ParallelSquaresWorkflow
 *
 * @param numbers - Array of integers to square.
 * @returns       - Sum of the squares of all input numbers.
 */
export async function ParallelSquaresWorkflow(numbers: number[]): Promise<number> {
  // Build all activity promises without awaiting individually so that Temporal
  // schedules them all in parallel (fan-out).
  const squarePromises: Promise<number>[] = numbers.map((n) => squareNumber(n));

  // Fan-in: wait for every activity to complete and collect results.
  const squares: number[] = await Promise.all(squarePromises);

  // Aggregate: sum the squared results.
  const total = squares.reduce((acc, val) => acc + val, 0);

  return total;
}

/**
 * Temporal Worker
 *
 * Connects to Temporal Cloud using API-key auth, registers
 * ParallelSquaresWorkflow and the squareNumber activity, then starts polling
 * the `parallel-squares-ts` task queue.
 *
 * Credentials are read exclusively from environment variables:
 *   TEMPORAL_API_KEY      – API key issued by Temporal Cloud
 *   TEMPORAL_ADDRESS      – <namespace>.tmprl.cloud:7233 (or similar)
 *   TEMPORAL_NAMESPACE    – Temporal Cloud namespace
 */

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';
import path from 'path';

const TASK_QUEUE = 'parallel-squares-ts';

async function main(): Promise<void> {
  const apiKey    = process.env.TEMPORAL_API_KEY;
  const address   = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  // NativeConnection is required for the Worker (uses the Rust core under the hood).
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: TASK_QUEUE,
    // workflowsPath must point to the compiled workflow module.
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  console.log(`[worker] Polling task queue "${TASK_QUEUE}" on namespace "${namespace}" …`);
  await worker.run();
}

main().catch((err) => {
  console.error('[worker] Fatal error:', err);
  process.exit(1);
});

/**
 * Temporal Client
 *
 * Connects to Temporal Cloud, starts ParallelSquaresWorkflow with the input
 * array [1, 2, 3, 4, 5], waits for the workflow to complete, and prints the
 * resulting sum to stdout.
 *
 * Credentials are read exclusively from environment variables:
 *   TEMPORAL_API_KEY      – API key issued by Temporal Cloud
 *   TEMPORAL_ADDRESS      – <namespace>.tmprl.cloud:7233 (or similar)
 *   TEMPORAL_NAMESPACE    – Temporal Cloud namespace
 *   ZEALT_RUN_ID          – Unique identifier for this run (used in workflow ID)
 */

import { Connection, Client } from '@temporalio/client';
import { ParallelSquaresWorkflow } from './workflows';

const TASK_QUEUE = 'parallel-squares-ts';
const INPUT      = [1, 2, 3, 4, 5];

async function main(): Promise<void> {
  const apiKey    = process.env.TEMPORAL_API_KEY;
  const address   = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId     = process.env.ZEALT_RUN_ID;

  if (!apiKey || !address || !namespace || !runId) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE, ZEALT_RUN_ID'
    );
  }

  const workflowId = `parallel-wf-${runId}`;

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  console.log(`[client] Starting workflow "${workflowId}" with input: [${INPUT.join(', ')}]`);

  const result = await client.workflow.execute(ParallelSquaresWorkflow, {
    taskQueue: TASK_QUEUE,
    workflowId,
    args: [INPUT],
  });

  console.log(`[client] Workflow completed. Sum of squares: ${result}`);
}

main().catch((err) => {
  console.error('[client] Fatal error:', err);
  process.exit(1);
});

/**
 * start.ts — Orchestrator for `npm start`
 *
 * 1. Spawns the compiled worker (dist/worker.js) as a background child process.
 * 2. Waits a moment for the worker to connect and begin polling.
 * 3. Runs the client inline: starts ParallelSquaresWorkflow, waits for the
 *    result, and prints it to stdout.
 * 4. Terminates the worker process and exits cleanly.
 */

import { spawn, ChildProcess } from 'child_process';
import { Connection, Client } from '@temporalio/client';
import { ParallelSquaresWorkflow } from './workflows';
import path from 'path';

const TASK_QUEUE = 'parallel-squares-ts';
const INPUT      = [1, 2, 3, 4, 5];

// ── helpers ────────────────────────────────────────────────────────────────

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function startWorker(): ChildProcess {
  const workerPath = path.resolve(__dirname, 'worker.js');
  const proc = spawn(process.execPath, [workerPath], {
    stdio: 'inherit',
    env: process.env,
  });

  proc.on('error', (err) => {
    console.error('[start] Worker process error:', err);
  });

  return proc;
}

// ── main ───────────────────────────────────────────────────────────────────

async function main(): Promise<void> {
  const apiKey    = process.env.TEMPORAL_API_KEY;
  const address   = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId     = process.env.ZEALT_RUN_ID;

  if (!apiKey || !address || !namespace || !runId) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE, ZEALT_RUN_ID'
    );
  }

  const workflowId = `parallel-wf-${runId}`;

  // 1. Launch worker in the background.
  console.log('[start] Launching worker …');
  const workerProc = startWorker();

  // 2. Give the worker time to connect and start polling before submitting work.
  await sleep(5000);

  // 3. Connect the client and execute the workflow.
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({ connection, namespace });

  console.log(`[start] Starting workflow "${workflowId}" with input: [${INPUT.join(', ')}]`);

  let result: number;
  try {
    result = await client.workflow.execute(ParallelSquaresWorkflow, {
      taskQueue: TASK_QUEUE,
      workflowId,
      args: [INPUT],
    });
  } finally {
    // 4. Always clean up the worker regardless of workflow success/failure.
    console.log('[start] Workflow finished. Shutting down worker …');
    workerProc.kill('SIGTERM');
    await connection.close();
  }

  // Print the final result — this is what the acceptance criteria check.
  console.log(`${result!}`);
}

main().catch((err) => {
  console.error('[start] Fatal error:', err);
  process.exit(1);
});

